def replay_infosets(g):
    """Replays g.set_infoset(...) calls."""
    g.set_infoset(g.root.children['Chamber 1'], g.root.children['Chamber 0'].infoset)
    g.set_infoset(g.root.children['Chamber 2'], g.root.children['Chamber 0'].infoset)
    g.set_infoset(g.root.children['Chamber 2'].children['Pull trigger'], g.root.children['Chamber 1'].children['Pull trigger'].infoset)
    g.set_infoset(g.root.children['Chamber 3'], g.root.children['Chamber 0'].infoset)
    g.set_infoset(g.root.children['Chamber 3'].children['Pull trigger'], g.root.children['Chamber 1'].children['Pull trigger'].infoset)
    g.set_infoset(g.root.children['Chamber 3'].children['Pull trigger'].children['Pull trigger'], g.root.children['Chamber 2'].children['Pull trigger'].children['Pull trigger'].infoset)
    g.set_infoset(g.root.children['Chamber 4'], g.root.children['Chamber 0'].infoset)
    g.set_infoset(g.root.children['Chamber 4'].children['Pull trigger'], g.root.children['Chamber 1'].children['Pull trigger'].infoset)
    g.set_infoset(g.root.children['Chamber 4'].children['Pull trigger'].children['Pull trigger'], g.root.children['Chamber 2'].children['Pull trigger'].children['Pull trigger'].infoset)
    g.set_infoset(g.root.children['Chamber 4'].children['Pull trigger'].children['Pull trigger'].children['Pull trigger'], g.root.children['Chamber 3'].children['Pull trigger'].children['Pull trigger'].children['Pull trigger'].infoset)
    g.set_infoset(g.root.children['Chamber 5'], g.root.children['Chamber 0'].infoset)
    g.set_infoset(g.root.children['Chamber 5'].children['Pull trigger'], g.root.children['Chamber 1'].children['Pull trigger'].infoset)
    g.set_infoset(g.root.children['Chamber 5'].children['Pull trigger'].children['Pull trigger'], g.root.children['Chamber 2'].children['Pull trigger'].children['Pull trigger'].infoset)
    g.set_infoset(g.root.children['Chamber 5'].children['Pull trigger'].children['Pull trigger'].children['Pull trigger'], g.root.children['Chamber 3'].children['Pull trigger'].children['Pull trigger'].children['Pull trigger'].infoset)
    g.set_infoset(g.root.children['Chamber 5'].children['Pull trigger'].children['Pull trigger'].children['Pull trigger'].children['Pull trigger'], g.root.children['Chamber 4'].children['Pull trigger'].children['Pull trigger'].children['Pull trigger'].children['Pull trigger'].infoset)
